mapper.select:
select l.id, l.applicant_type, CASE l.applicant_type WHEN 'STUDENT' THEN s.name WHEN 'TEACHER' THEN t.name END as applicant_name, s.name as student_name, COALESCE(CASE l.applicant_type WHEN 'STUDENT' THEN head_t.name WHEN 'TEACHER' THEN a.name END, '待分配') as approver_name, l.leave_type, l.start_time, l.end_time, l.status, l.create_time from leave_request l left join student s on l.student_id = s.id left join teacher t on l.applicant_id = t.id and l.applicant_type = 'TEACHER' left join teacher head_t on l.approver_id = head_t.id and l.applicant_type = 'STUDENT' left join admin a on l.approver_id = a.id and l.applicant_type = 'TEACHER'
and s.name like concat('%', #{studentName}, '%') and l.leave_type = #{leaveType} and l.status = #{status}
order by l.id desc

select l.id, l.applicant_type, CASE l.applicant_type WHEN 'STUDENT' THEN s.name WHEN 'TEACHER' THEN t.name END as applicant_name, COALESCE(CASE l.applicant_type WHEN 'STUDENT' THEN head_t.name WHEN 'TEACHER' THEN a.name END, '待分配') as approver_name, l.leave_type, l.start_time, l.end_time, l.reason, l.status, l.is_course_rescheduled, l.create_time from leave_request l left join student s on l.applicant_id = s.id and l.applicant_type = 'STUDENT' left join teacher t on l.applicant_id = t.id and l.applicant_type = 'TEACHER' left join teacher head_t on l.approver_id = head_t.id and l.applicant_type = 'STUDENT' left join admin a on l.approver_id = a.id and l.applicant_type = 'TEACHER'
and l.status = #{status} and l.applicant_id = #{applicantId} and l.applicant_type = #{applicantType}
order by l.id desc

select l.id, l.applicant_type, CASE l.applicant_type WHEN 'STUDENT' THEN s.name WHEN 'TEACHER' THEN t.name END as applicant_name, s.name as student_name, l.leave_type, l.start_time, l.end_time, l.reason, l.create_time from leave_request l left join student s on l.student_id = s.id left join teacher t on l.applicant_id = t.id and l.applicant_type = 'TEACHER'
and l.status = #{status} and l.approver_id = #{approverId}
order by l.id desc
